export const findCycles=(t,e,n=16)=>{const s=[],o=new Set,r=new Set([e]),i=[e],a=p=>{if(i.length>n)return;const f=t.get(p);if(!f?.imports?.internal)return;const d=new Set;for(const t of f.imports.imports)t.filePath&&!t.isTypeOnly&&d.add(t.filePath);for(const[t]of f.imports.internal)d.has(t)&&(t!==e?o.has(t)||r.has(t)||(i.push(t),r.add(t),a(t),r.delete(t),i.pop()):s.push([...i,t]));o.add(p)};return a(e),s};